SUPPORTED_SYMBOLS = {stock["symbol"] for stock in SUPPORTED_STOCKS}
SUPPORTED_BY_SYMBOL = {stock["symbol"]: stock for stock in SUPPORTED_STOCKS}

def normalize_ticker(symbol):
    return str(symbol or "").strip().upper().replace(".", "-").replace("/", "-")

def find_supported_stock(symbol):
    return SUPPORTED_BY_SYMBOL.get(normalize_ticker(symbol))

def search_supported_stocks(query, limit=8):
    normalized_query = str(query or "").strip().lower()
    symbol_query = normalized_query.replace(".", "-").replace("/", "-")
    if not normalized_query:
        return []

    matches = []
    for stock in SUPPORTED_STOCKS:
        symbol = stock["symbol"].lower()
        name = stock["name"].lower()
        aliases = [alias.lower() for alias in stock.get("aliases", [])]
        rank = 99

        if symbol == symbol_query or normalized_query in aliases:
            rank = 0
        elif symbol.startswith(symbol_query):
            rank = 1
        elif name.startswith(normalized_query):
            rank = 2
        elif any(normalized_query in alias for alias in aliases):
            rank = 3
        elif symbol_query in symbol:
            rank = 4
        elif normalized_query in name:
            rank = 5

        if rank < 99:
            matches.append((rank, stock["symbol"], stock))

    matches.sort(key=lambda item: (item[0], item[1]))
    return [item[2] for item in matches[:limit]]
